import{_ as l,I as a,o as i,c,j as e,a as n,J as o}from"./chunks/framework.DYZFTu11.js";const b=JSON.parse('{"title":"《α星篇·其九：黎明前夜》","description":"","frontmatter":{},"headers":[],"relativePath":"zh_cn/novels/shuangxingluji/chapter-11.md","filePath":"zh_cn/novels/shuangxingluji/chapter-11.md","lastUpdated":1773498699000}'),p={name:"zh_cn/novels/shuangxingluji/chapter-11.md"};function d(h,t,u,_,g,m){const s=a("NolebaseGitContributors"),r=a("NolebaseGitChangelog");return i(),c("div",null,[t[0]||(t[0]=e("h1",{id:"《α星篇·其九-黎明前夜》",tabindex:"-1"},[e("strong",null,"《α星篇·其九：黎明前夜》"),n(),e("a",{class:"header-anchor",href:"#《α星篇·其九-黎明前夜》","aria-label":"Permalink to “《α星篇·其九：黎明前夜》”"},"​")],-1)),t[1]||(t[1]=e("p",null,[e("strong",null,"《α星篇·其九：黎明前夜》"),n(' 我接过那瓶莹莹发光的药水，玻璃瓶壁触手生温，像是捧着一颗跳动的心脏，内里流转的液体如同星河般璀璨夺目，在幽暗的环境中映照出变幻莫测的光晕。一股奇异的暖流瞬间从指尖蔓延至全身，每一根神经末梢都在欢欣雀跃，仿佛这液体本就属于我的一部分，此刻终于挣脱束缚回归本源。我深吸一口气，潮湿的空气中混杂着血腥味与硝烟的气息，毫不犹豫地拔开那个镶嵌着古老符文的瓶塞，仰头将药水一饮而尽。 刹那间，世界天旋地转。我的意识突然抽离，如同从第一人称视角切换成了上帝视角，灵魂被强行拽出躯壳，悬浮在虚无的黑暗之中。在这片混沌中，我看见那些被封印的力量正在苏醒，它们如同被囚禁千年的猛兽，发出震耳欲聋的咆哮，冲破无形的桎梏，在虚空中绽放出令人目眩的璀璨光芒。每一道光芒都蕴含着毁天灭地的力量，在我的灵魂深处引发共鸣，记忆的碎片如走马灯般闪现——那些被遗忘的战斗，被封印的能力，被抹去的荣耀。当视线重新聚焦时，所有力量都已回归，但脑海中却响起蛊惑的低语，像毒蛇般缠绕着我的理智，甜美的诱惑中暗藏致命剧毒。我紧咬牙关，额角青筋暴起，用意志筑起铜墙铁壁，将这些阴暗的絮语隔绝在外，冷汗顺着脊背蜿蜒而下。 就在这时，灵裔军团正裹挟着腐臭的活死人如潮水般蜂拥而入，腐朽的气息瞬间充斥整个空间，令人作呕的尸臭与血腥味几乎凝成实质。叶子的枪火在黑暗中划出炽热的轨迹，每一发子弹都精准地穿透敌人的头颅，爆开的脑浆在墙上绘出诡异的抽象画，但敌人的数量实在太多，它们踩着同伴的尸体继续前进，空洞的眼窝里跳动着幽绿的鬼火。我本能地抬手，掌心凝聚起耀眼的奥术能量，空气因高温而扭曲变形，一枚足有马车大小的奥术飞弹呼啸而出，在空中划出炫目的轨迹，将前排数十名敌人炸得粉碎，残肢断臂如雨点般落下，黏腻的内脏碎片啪嗒啪嗒地砸在地面上。 幸存的灵裔立刻调转矛头，远程施法者开始吟唱晦涩的咒语，法杖尖端闪烁着危险的光芒，空气中的魔法元素躁动不安；近战部队则如潮水般涌来，锋利的刀刃在黑暗中反射着森冷的光，金属摩擦声刺耳难忍。但他们的动作在我眼中却像被按下了慢放键，每一个细微的表情、每一次肌肉的收缩都清晰可见，甚至连他们睫毛的颤动都逃不过我的眼睛。我轻盈侧身，寒光闪过，最先冲来的灵裔头颅应声飞起，脸上还凝固着狰狞的表情，无头的躯体因惯性继续前冲了几步才轰然倒地。旁边的施法者慌乱结印，干枯的手指扭曲成古怪的姿势，可法阵尚未成型，我的指尖已射出一道银光，他的咽喉顿时绽放出一朵血花，不可置信地瞪大眼睛，喉间发出咯咯的声响，缓缓倒下。 "这不可能！"惊恐的尖叫在敌阵中炸开，无数火球、冰锥、暗影箭如暴雨般袭来，炽热的火浪与刺骨的寒冰交织成死亡之网，却连我的衣角都碰不到——我在弹幕中穿梭，身形如鬼魅般飘忽不定，每一次闪现都伴随着一个敌人的倒下，他们的惨叫声此起彼伏。我的每一击都精准致命，奥术能量在体内奔涌，血管中流淌的不再是血液而是纯粹的魔力，让我仿佛化身为死神的化身，所经之处只余尸山血海。 当最后一个灵裔倒下时，粘稠的血液已经漫过脚踝。我注意到这些尸体竟未如往常般复活，破碎的躯壳安静地躺在血泊中，再没有蠕动重组的迹象。空气中弥漫着诡异的寂静，连风声都停止了，只有血滴从天花板坠落的声音清晰可闻。看来幕后黑手终于坐不住了——果然，地面突然剧烈震动，无数猩红的藤蔓破土而出，带着凌厉的破空声向我袭来，每一根都粗如成年男子的手臂，表面布满尖锐的倒刺，滴落着腐蚀性的黏液。我纵身跃起，在空中划出一道优美的弧线，双手凝聚出两柄光刃，将袭来的藤蔓尽数斩断。断裂的藤蔓喷溅出腐蚀性的液体，在地面上烧出缕缕青烟，混凝土被侵蚀出蜂窝状的孔洞。 在激烈的交锋中，那个一直将我们玩弄于股掌之间的身影终于显现——她悬浮在半空，苍白的脸上带着扭曲的笑容，紫黑的嘴唇咧到不可思议的弧度，双手操控着更多藤蔓从四面八方袭来，整个空间仿佛变成了她的狩猎场。但随着战斗持续，她的动作开始变得迟缓，额角渗出细密的汗珠，呼吸也变得紊乱，华丽的黑袍已经被汗水浸透。就在我抓住破绽，准备给予致命一击时，她突然发出一声凄厉的尖叫，整个身体爆裂开来，化作一团血雾消散在空气中，只余下刺鼻的硫磺味在鼻腔中灼烧。 与此同时，一阵强烈的眩晕感席卷而来，我的视线开始模糊，眼前的景象分裂成无数重叠的残影，四肢如灌了铅般沉重。体内的力量正在急速流失，像是有人拔掉了塞子的浴缸，意识如同退潮般迅速消逝。在陷入黑暗前的最后一刻，我听见自己沉重倒地的闷响，以及叶子惊慌失措的呼喊声，那声音越来越远，最终归于永恒的寂静，仿佛被厚重的幕布隔绝在另一个世界。')],-1)),o(s),o(r)])}const x=l(p,[["render",d]]);export{b as __pageData,x as default};
